import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ArrowLeft, Camera, Upload, ShieldCheck, ShieldAlert, Loader2, User, Check, X, FileText, Info, Fingerprint, Zap, Sparkles, Activity, Target, HardDrive, RefreshCw } from 'lucide-react';
import { GoogleGenAI, Type } from '@google/genai';
import { auth, db } from '../services/firebaseConfig';
import { uploadFileToStorage, deductCoins, AI_COSTS } from '../services/firestoreService';
import { generateSecureId } from '../utils/idUtils';
import { resizeImage } from '../utils/imageUtils';
import { UserProfile, BiometricShard } from '../types';
import { NeuralRetinaGraph } from './NeuralRetinaGraph';

interface IdentityLabProps {
  onBack: () => void;
  userProfile: UserProfile | null;
  onOpenManual?: () => void;
}

export const IdentityLab: React.FC<IdentityLabProps> = ({ onBack, userProfile, onOpenManual }) => {
  const [step, setStep] = useState<'upload' | 'capture' | 'verify' | 'result'>('upload');
  const [idImage, setIdImage] = useState<string | null>(null);
  const [selfieImage, setSelfieImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [processStatus, setProcessStatus] = useState('');
  const [shard, setShard] = useState<BiometricShard | null>(null);
  const [error, setError] = useState<string | null>(null);

  const [isCameraActive, setIsCameraActive] = useState(false);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const dispatchLog = (text: string, type: 'info' | 'success' | 'warn' | 'error' = 'info') => {
      window.dispatchEvent(new CustomEvent('neural-log', { detail: { text: `[Biometric] ${text}`, type } }));
  };

  const startCamera = async () => {
    setIsCameraActive(true);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 480, height: 480, facingMode: 'user' } });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        await videoRef.current.play();
      }
    } catch (err) {
      setError("Camera access refused.");
      setIsCameraActive(false);
    }
  };

  const stopCamera = () => {
    if (videoRef.current?.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      videoRef.current.srcObject = null;
    }
    setIsCameraActive(false);
  };

  const captureSelfie = () => {
    if (videoRef.current && canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      if (ctx) {
        canvasRef.current.width = videoRef.current.videoWidth;
        canvasRef.current.height = videoRef.current.videoHeight;
        ctx.drawImage(videoRef.current, 0, 0);
        const b64 = canvasRef.current.toDataURL('image/jpeg', 0.85);
        setSelfieImage(b64);
        stopCamera();
        setStep('verify');
      }
    }
  };

  const handleIdUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) {
      const b64 = await resizeImage(e.target.files[0], 1024, 0.7);
      setIdImage(b64);
      setStep('capture');
      startCamera();
    }
  };

  const runBiometricAudit = async () => {
    if (!idImage || !selfieImage || !userProfile) return;
    setIsProcessing(true);
    setError(null);
    setProcessStatus("Initializing Biometric Handshake...");
    dispatchLog("Starting multi-stage verification cycle.", "info");

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Phase 1: OCR and Liveness Detection (Gemini 2.5 Flash)
      setProcessStatus("Phase 1: Ingesting ID Metadata...");
      const flashResponse = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: idImage.split(',')[1], mimeType: 'image/jpeg' } },
            { text: "Extract Name and Expiry Date from this ID. Return JSON: { name: string, expiry: string, documentType: string }" }
          ]
        },
        config: { responseMimeType: 'application/json' }
      });
      const idDetails = JSON.parse(flashResponse.text || '{}');
      dispatchLog(`ID Ingested: ${idDetails.name || 'Unknown'}`, 'success');

      // Phase 2: High-Fidelity Biometric Comparison (Gemini 3 Pro)
      setProcessStatus("Phase 2: Executing Retina Mesh Audit...");
      const proResponse = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [
            { inlineData: { data: idImage.split(',')[1], mimeType: 'image/jpeg' }, text: "Passport/ID Image" },
            { inlineData: { data: selfieImage.split(',')[1], mimeType: 'image/jpeg' }, text: "Live Selfie Image" },
            { text: `Act as a Biometric Identity Auditor. Compare the face in the Passport/ID against the Live Selfie. 
              Analyze inter-pupillary distance, jawline structure, and nasal bridges. 
              Look for signs of spoofing (photos of screens). 
              Return a detailed analysis and a similarity score (0-100).
              Also extract a logic graph of your verification steps.

              Return ONLY JSON:
              {
                "score": number,
                "verdict": "PASS" | "FAIL" | "SUSPICIOUS",
                "analysis": "detailed markdown string",
                "graph": {
                   "nodes": [{"id": "n1", "label": "Iris Alignment", "type": "verification"}, ...],
                   "links": [{"source": "n1", "target": "n2", "label": "Verified"}]
                }
              }`
            }
          ]
        },
        config: { 
            responseMimeType: 'application/json',
            thinkingConfig: { thinkingBudget: 8000 }
        }
      });

      const auditResult = JSON.parse(proResponse.text || '{}');
      const shardId = generateSecureId();

      const newShard: BiometricShard = {
        id: shardId,
        userId: userProfile.uid,
        timestamp: Date.now(),
        similarityScore: auditResult.score,
        verdict: auditResult.verdict,
        idDetails: idDetails,
        analysis: auditResult.analysis,
        idImage: idImage,
        selfieImage: selfieImage,
        audit: {
            graph: auditResult.graph,
            probes: [],
            coherenceScore: auditResult.score,
            StructuralCoherenceScore: auditResult.score,
            LogicalDriftRisk: 'Low',
            AdversarialRobustness: 'High',
            driftRisk: 'Low',
            robustness: 'High',
            timestamp: Date.now()
        }
      };

      setShard(newShard);
      setStep('result');

      if (auth.currentUser) {
          await deductCoins(auth.currentUser.uid, AI_COSTS.TECHNICAL_EVALUATION);
          // In a real app, we'd save this to Firestore too
      }

      dispatchLog(`Verification Complete. Verdict: ${auditResult.verdict}`, auditResult.verdict === 'PASS' ? 'success' : 'warn');
    } catch (e: any) {
      setError(e.message || "Refraction Fault");
      dispatchLog(`Audit Failure: ${e.message}`, "error");
    } finally {
