    id: string;
    time: string;
    text: string;
    type: 'info' | 'error' | 'success' | 'warn' | 'shadow' | 'audit' | 'input' | 'output' | 'trace' | 'loop';
    meta?: any;
}

const App: React.FC = () => {
  const [language, setLanguage] = useState<'en' | 'zh'>('en');
  const t = UI_TEXT[language];

  const [activeViewID, setActiveViewID] = useState<ViewID>(() => {
