            addSystemLog("Mobile Refraction Triggered: Switching to Podcast Feed Layout.", "info");
        }
    };
    window.addEventListener('resize', handleGlobalResize);
    handleGlobalResize();
    return () => window.removeEventListener('resize', handleGlobalResize);
